  slides.push({ chapter: 'TUYẾN', title: 'Cơ cấu doanh số CL / NCL / NT', message: 'Tuyến dẫn đầu về doanh thu chưa chắc là tuyến có dư địa CST lớn nhất.', body: `<div class="two-col"><div class="panel">${stacked(route)}</div>${barsPanel(d.cstOpportunity.routes, 'Dư địa CST theo tuyến', { value: 'remainAmount', limit: 4, color: '#E9B949' })}</div>` });
