  slides.push({ chapter: 'NHÂN VIÊN', title: 'Nhân viên cần can thiệp ngay', message: 'Chậm target và thiếu Xu tháng là hai tín hiệu khác nhau; cần giao hành động riêng.', body: `<div class="two-col"><div class="panel"><h3>CHẬM TARGET THÁNG</h3>${table([{ t: 'NV' }, { t: 'Đạt', c: 'r' }, { t: 'Thiếu', c: 'r' }], target.slow.slice(0, 7).map((x) => [x.empCode, { t: rate(x.rate), c: 'r' }, { t: short(Math.max(0, x.gap)), c: 'r' }]), { empty: 'Không có NV dưới 80% target.' })}</div><div class="panel"><h3>THIẾU NHỊP XU THÁNG</h3>${table([{ t: 'NV' }, { t: 'Điểm tháng', c: 'r' }, { t: 'Xu tháng', c: 'r' }, { t: 'Đạt', c: 'r' }], sx.monthlyWarnings.slice(0, 7).map((x) => [x.empCode, { t: num(x.diem_thang, 2), c: 'r' }, { t: num(x.xu_thang, 2), c: 'r' }, { t: rate(x.monthlyRate), c: 'r' }]), { empty: 'Không có cảnh báo Xu tháng.' })}</div></div>` });
  slides.push({ chapter: 'ĐƠN VỊ', title: 'Độ phủ đơn vị có phát sinh trong tuần', message: 'Số đơn vị phát sinh phản ánh độ phủ; mức tập trung cho biết rủi ro phụ thuộc.', body: `${kpis([{ value: num(t.unitCount), label: 'Đơn vị có doanh thu' }, { value: rate(d.concentration.top5Share), label: 'Tỷ trọng Top 5' }, { value: rate(d.concentration.top10Share), label: 'Tỷ trọng Top 10' }, { value: num(d.cstOpportunity.units.length), label: 'Đơn vị còn CST' }])}<div class="chart-hero compact">${pareto(topUnits)}</div>` });
