  slides.push({ chapter: 'ĐƠN VỊ', title: 'Đơn vị có dư địa CST lớn', message: 'Dư địa được xếp theo giá trị còn lại, đi kèm doanh thu hiện tại và owner.', body: `<div class="two-col"><div class="panel">${hBars(d.cstOpportunity.units, { value: 'remainAmount', limit: 8, color: '#E9B949' })}</div>${insight('Đơn vị ưu tiên', `${d.cstOpportunity.units[0]?.label || 'Chưa có dữ liệu'} còn dư địa ${short(d.cstOpportunity.units[0]?.remainAmount)}; owner: ${d.cstOpportunity.units[0]?.owners.slice(0, 4).join(', ') || 'chưa xác định'}.`, 'gold')}</div>` });
